// ─── HELPERS ──────────────────────────────────────────────────────────────────
function getBizDates() {
  const res = []; let d = new Date(), add = 0;
  while (add < 2) { d = new Date(d.getTime()+864e5); if (d.getDay()&&d.getDay()<6) add++; }
  for (let i=0; res.length<10; i++) {
    const nd = new Date(d.getTime()+i*864e5);
    if (nd.getDay()&&nd.getDay()<6) res.push(nd);
  }
  return res;
}
function getFrete(addr) {
  if (!addr||addr.length<5) return null;
  let h=0; for (const c of addr) h=(h*31+c.charCodeAt(0))%97;
  const km=2+(h%13);
  return km>15?{err:true,km}:{km:+km.toFixed(1),fee:km<=5?10:km<=10?15:20};
}
const R   = n => `R$ ${n.toFixed(2).replace('.',',')}`;
const fmt = d => d.toLocaleDateString('pt-BR',{weekday:'short',day:'2-digit',month:'2-digit'});

// ─── HOOK RESPONSIVO ──────────────────────────────────────────────────────────
function useWindowWidth() {
  const [w, setW] = useState(typeof window !== 'undefined' ? window.innerWidth : 1200);
  useEffect(() => {
    const fn = () => setW(window.innerWidth);
    window.addEventListener('resize', fn);
    return () => window.removeEventListener('resize', fn);
  }, []);
  return w;
}

