// ─── BOTÕES ───────────────────────────────────────────────────────────────────
function BtnRed({ children, onClick, style={}, disabled=false }) {
  return (
    <button onClick={onClick} disabled={disabled} style={{
      background:disabled?'rgba(196,30,36,0.3)':RED, border:`1px solid ${disabled?'rgba(196,30,36,0.3)':RED2}`,
      color:CREAM, padding:'13px 28px', fontSize:11, letterSpacing:'0.18em', textTransform:'uppercase',
      cursor:disabled?'not-allowed':'pointer', fontFamily:SANS, fontWeight:400,
      transition:'all .2s', opacity:disabled?.5:1, borderRadius:0, ...style,
    }}
    onMouseEnter={e=>{if(!disabled)e.currentTarget.style.background=RED2;}}
    onMouseLeave={e=>{if(!disabled)e.currentTarget.style.background=RED;}}
    >{children}</button>
  );
}
function BtnOutline({ children, onClick, style={} }) {
  return (
    <button onClick={onClick} style={{
      background:'transparent', border:`1px solid ${BORDER}`, color:MUTED,
      padding:'13px 28px', fontSize:11, letterSpacing:'0.18em', textTransform:'uppercase',
      cursor:'pointer', fontFamily:SANS, fontWeight:400, transition:'all .2s', borderRadius:0, ...style,
    }}
    onMouseEnter={e=>{e.currentTarget.style.borderColor=GOLD;e.currentTarget.style.color=GOLD;}}
    onMouseLeave={e=>{e.currentTarget.style.borderColor=BORDER;e.currentTarget.style.color=MUTED;}}
    >{children}</button>
  );
}


