// ─── APP ──────────────────────────────────────────────────────────────────────
export default function App() {
  const w = useWindowWidth();
  const isMobile = w < 768;
  const isTablet = w < 1024;

  const [pg,        setPg]       = useState('home');
  const [cart,      setCart]     = useState([]);
  const [user,      setUser]     = useState(null);
  const [loginOpen, setLoginOpen]= useState(false);
  const [menuOpen,  setMenuOpen] = useState(false);
  const [modal,     setModal]    = useState(null);
  const [cust,      setCust]     = useState({sz:'M',base:BASES[0],creme:CREMES[0],calda:CALDAS[0],extras:[],toppings:[],qty:1});
  const [dlv,       setDlv]      = useState('pickup');
  const [addr,      setAddr]     = useState('');
  const [selDate,   setSelDate]  = useState(null);
  const [pay,       setPay]      = useState('pix');
  const [cardF,     setCardF]    = useState({num:'',name:'',exp:'',cvv:''});
  const [mpLoading, setMpLoading] = useState(false);
  const [mpError,   setMpError]   = useState('');

  // ── RETORNO DO MERCADO PAGO ──────────────────────────────────────────────
  // O MP redireciona de volta pra cá com ?status=success|failure|pending
  // depois do pagamento. Aqui a gente lê isso, dispara a notificação
  // (email + link de WhatsApp) e leva o cliente pra tela de confirmação.
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const status = params.get('status');
    if (!status) return;

    // limpa a URL pra não repetir esse fluxo se a pessoa der F5
    window.history.replaceState({}, '', window.location.pathname);

    if (status === 'success' || status === 'approved') {
      const pendingRaw = sessionStorage.getItem('bada_pending_order');
      if (pendingRaw) {
        try {
          const pending = JSON.parse(pendingRaw);
          fetch('/api/notify-order', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(pending),
          }).catch(err => console.error('Erro ao notificar pedido:', err));
        } catch (e) {
          console.error('Erro ao ler pedido pendente:', e);
        }
        sessionStorage.removeItem('bada_pending_order');
      }
      setCart([]);
      setPg('confirmation');
    } else if (status === 'failure') {
      setMpError('Pagamento não aprovado. Tente novamente ou finalize pelo WhatsApp.');
      setPg('checkout');
    } else if (status === 'pending') {
      setMpError('Pagamento em análise (ex: boleto ou PIX pendente). Você recebe a confirmação assim que for aprovado.');
      setPg('checkout');
    }
    window.scrollTo({ top: 0 });
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const dates  = useMemo(getBizDates,[]);
  const frete  = useMemo(()=>dlv==='delivery'?getFrete(addr):{km:0,fee:0},[dlv,addr]);
  const sub    = cart.reduce((s,i)=>s+i.total,0);
  const total  = sub+(frete?.fee||0);
  const canPay = selDate&&(dlv==='pickup'||(frete&&!frete.err&&frete.fee!=null));

  const go = p => { setPg(p); setMenuOpen(false); window.scrollTo({top:0,behavior:'smooth'}); };

  // ── CHECKOUT MERCADO PAGO ──────────────────────────────────────────────────
  const handleMPCheckout = async () => {
    setMpLoading(true);
    setMpError('');
    try {
      const items = cart.map(item => ({
        id: String(item.pid),
        title: item.name + (item.dobroCreme ? ' (Dobro de Creme)' : ''),
        description: `${item.sz==='M'?'Médio 8 fatias':'Grande 12 fatias'} · Qtd: ${item.qty}`,
        quantity: item.qty,
        unit_price: item.unit,
        currency_id: 'BRL',
      }));

      if (dlv === 'delivery' && frete?.fee) {
        items.push({
          id: 'frete',
          title: 'Frete',
          quantity: 1,
          unit_price: frete.fee,
          currency_id: 'BRL',
        });
      }

      const pendingOrder = {
        cart, dlv, addr, selDate, frete, total,
        customer: user || 'visitante',
      };

      const res = await fetch('/api/create-preference', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          items,
          payer: user ? { email: user } : undefined,
          // Guarda um resumo do pedido na própria preferência do MP.
          // Assim o webhook consegue montar a notificação mesmo que
          // o cliente feche o navegador antes de voltar pro site.
          metadata: {
            order_summary: JSON.stringify(pendingOrder).slice(0, 2000),
          },
        }),
      });

      const data = await res.json();
      if (!res.ok) throw new Error(data.error || 'Erro ao iniciar pagamento');

      // Salva pedido no sessionStorage para recuperar após o redirect
      sessionStorage.setItem('bada_pending_order', JSON.stringify(pendingOrder));

      // Redireciona para o checkout do Mercado Pago
      // sandbox_init_point = teste | init_point = produção
      window.location.href = data.init_point;

    } catch (err) {
      setMpError('Não foi possível iniciar o pagamento. Tente novamente ou use o WhatsApp.');
      console.error(err);
    } finally {
      setMpLoading(false);
    }
  };

  const openTradicional = p => { setModal({produto:p,modo:'tradicional'}); setCust({sz:'M',extras:[],toppings:[],dobroCreme:false,qty:1}); };
  const openPersonalizada = () => { setModal({produto:PRODUTO_PERSONALIZADA,modo:'personalizada'}); setCust({sz:'M',base:BASES[0],creme:CREMES[0],calda:CALDAS[0],extras:[],toppings:[],dobroCreme:false,qty:1}); };

  const toggleExtra   = c  => setCust(v=>({...v,extras:  v.extras.includes(c)  ?v.extras.filter(x=>x!==c)  :[...v.extras,  c]}));
  const toggleTopping = id => setCust(v=>({...v,toppings:v.toppings.includes(id)?v.toppings.filter(x=>x!==id):[...v.toppings,id]}));

  const itemPrice = () => {
    if(!modal) return 0;
    const dobroVal = cust.dobroCreme ? (modal.produto.id===6 ? 65 : DOBRO_CREME_PRICE) : 0;
    return (modal.produto.prices[cust.sz]+cust.extras.length*EXTRA_PRICE+cust.toppings.length*TOPPING_PRICE+dobroVal)*cust.qty;
  };

  const addToCart = () => {
    const p=modal.produto;
    const dobroVal = cust.dobroCreme ? (p.id===6 ? 65 : DOBRO_CREME_PRICE) : 0;
    const unit=p.prices[cust.sz]+cust.extras.length*EXTRA_PRICE+cust.toppings.length*TOPPING_PRICE+dobroVal;
    const entry={id:Date.now(),pid:p.id,name:p.name,tipo:modal.modo,sz:cust.sz,extras:[...cust.extras],toppings:[...cust.toppings],dobroCreme:cust.dobroCreme,qty:cust.qty,unit,total:unit*cust.qty};
    if(modal.modo==='personalizada'){entry.base=cust.base;entry.creme=cust.creme;entry.calda=cust.calda;}
    setCart(c=>[...c,entry]);
    setModal(null);
  };

  // Padding horizontal responsivo
  const px = isMobile ? '5%' : '5%';

  // ── CSS GLOBAL ────────────────────────────────────────────────────────────
  const globalCSS = `
    @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,500;1,300;1,400;1,500&family=DM+Sans:wght@300;400;500&display=swap');
    *,*::before,*::after{box-sizing:border-box;margin:0;padding:0;}
    html{scroll-behavior:smooth;-webkit-text-size-adjust:100%;}
    body{overflow-x:hidden;}
    ::selection{background:${RED};color:${CREAM};}
    a{text-decoration:none;transition:opacity .2s;-webkit-tap-highlight-color:transparent;}
    button{-webkit-tap-highlight-color:transparent;touch-action:manipulation;}
    select option{background:${BG3};color:${CREAM};}
    input:focus,select:focus{border-color:rgba(201,169,110,.5)!important;outline:none;}

    @keyframes fadeUp{from{opacity:0;transform:translateY(20px)}to{opacity:1;transform:translateY(0)}}
    @keyframes fadeIn{from{opacity:0}to{opacity:1}}
    @keyframes slideDown{from{opacity:0;transform:translateY(-10px)}to{opacity:1;transform:translateY(0)}}

    .ha1{animation:fadeUp .8s .2s both}
    .ha2{animation:fadeUp .8s .4s both}
    .ha3{animation:fadeUp .8s .6s both}
    .ha4{animation:fadeUp .8s .8s both}
    .hfade{animation:fadeIn 1.2s .1s both}
    .slide-down{animation:slideDown .25s both}

    .prod-card{transition:transform .25s,border-color .25s;cursor:pointer;}
    @media(hover:hover){
      .prod-card:hover{transform:translateY(-3px);border-color:rgba(196,30,36,.35)!important;}
      .prod-card:hover .pimg{transform:scale(1.05);}
    }
    .pimg{transition:transform .4s ease;}

    .nav-link:hover{color:${RED}!important;}
    .diff-card:hover{border-color:rgba(196,30,36,.25)!important;background:rgba(196,30,36,.03)!important;}
    .social-link:hover{border-color:${RED}!important;color:${RED}!important;}

    .red-line::before{
      content:'';display:inline-block;width:24px;height:1px;
      background:${RED};vertical-align:middle;margin-right:10px;opacity:.8;
    }

    /* Scrollbar */
    ::-webkit-scrollbar{width:4px;}
    ::-webkit-scrollbar-track{background:${BG};}
    ::-webkit-scrollbar-thumb{background:rgba(201,169,110,.25);}

    /* Safe area para celulares com notch */
    .safe-bottom{padding-bottom:env(safe-area-inset-bottom,0px);}
  `;

  // ── NAV ───────────────────────────────────────────────────────────────────
  const Nav = () => (
    <nav style={{
      position:'sticky',top:0,zIndex:100,overflow:'visible',
      background:'rgba(10,9,8,0.97)',backdropFilter:'blur(16px)',
      borderBottom:`1px solid ${BORDER}`,
      padding:`0 ${px}`,display:'flex',alignItems:'center',
      justifyContent:'space-between',height:isMobile?140:220,
    }}>
      <div onClick={()=>go('home')} style={{cursor:'pointer',position:'relative',zIndex:101}}>
        <LogoBada height={isMobile?180:304}/>
      </div>

      {/* Desktop nav */}
      {!isMobile && (
        <div style={{display:'flex',gap:28,alignItems:'center'}}>
          <button className="nav-link" onClick={()=>go('menu')} style={{background:'transparent',border:'none',color:MUTED,fontSize:10,letterSpacing:'0.18em',textTransform:'uppercase',cursor:'pointer',fontFamily:SANS,transition:'color .2s'}}>Cardápio</button>
          {user
            ?<span style={{fontSize:11,color:GOLD}}>{user.split(' ')[0]}</span>
            :<button className="nav-link" onClick={()=>setLoginOpen(true)} style={{background:'transparent',border:'none',color:MUTED,fontSize:10,letterSpacing:'0.18em',textTransform:'uppercase',cursor:'pointer',fontFamily:SANS,transition:'color .2s'}}>Entrar</button>
          }
          <button onClick={()=>go('cart')} style={{
            position:'relative',background:'transparent',border:`1px solid ${BORDER}`,color:CREAM,
            padding:'9px 20px',fontSize:10,letterSpacing:'0.18em',textTransform:'uppercase',cursor:'pointer',fontFamily:SANS,transition:'all .2s',
          }}
          onMouseEnter={e=>{e.currentTarget.style.borderColor=RED;e.currentTarget.style.color=RED;}}
          onMouseLeave={e=>{e.currentTarget.style.borderColor=BORDER;e.currentTarget.style.color=CREAM;}}
          >
            Carrinho
            {cart.length>0&&<span style={{position:'absolute',top:-8,right:-8,background:RED,color:CREAM,borderRadius:'50%',width:18,height:18,fontSize:9,fontWeight:500,display:'inline-flex',alignItems:'center',justifyContent:'center'}}>{cart.length}</span>}
          </button>
        </div>
      )}

      {/* Mobile: ícones de carrinho + menu hamburguer */}
      {isMobile && (
        <div style={{display:'flex',alignItems:'center',gap:16}}>
          <button onClick={()=>go('cart')} style={{
            position:'relative',background:'transparent',border:'none',cursor:'pointer',
            color:MUTED,padding:4,transition:'color .2s',
          }}>
            {/* Ícone carrinho SVG */}
            <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
              <path d="M6 2 3 6v14a2 2 0 002 2h14a2 2 0 002-2V6l-3-4z"/><line x1="3" y1="6" x2="21" y2="6"/><path d="M16 10a4 4 0 01-8 0"/>
            </svg>
            {cart.length>0&&<span style={{position:'absolute',top:-4,right:-4,background:RED,color:CREAM,borderRadius:'50%',width:16,height:16,fontSize:8,fontWeight:600,display:'inline-flex',alignItems:'center',justifyContent:'center'}}>{cart.length}</span>}
          </button>
          {/* Hamburguer */}
          <button onClick={()=>setMenuOpen(m=>!m)} style={{background:'transparent',border:'none',cursor:'pointer',padding:4,display:'flex',flexDirection:'column',gap:5}}>
            <span style={{display:'block',width:22,height:1.5,background:menuOpen?RED:MUTED,transition:'all .2s',transform:menuOpen?'rotate(45deg) translate(4px,4px)':'none'}}/>
            <span style={{display:'block',width:22,height:1.5,background:menuOpen?'transparent':MUTED,transition:'all .2s',opacity:menuOpen?0:1}}/>
            <span style={{display:'block',width:22,height:1.5,background:menuOpen?RED:MUTED,transition:'all .2s',transform:menuOpen?'rotate(-45deg) translate(4px,-4px)':'none'}}/>
          </button>
        </div>
      )}

      {/* Mobile dropdown menu */}
      {isMobile && menuOpen && (
        <div className="slide-down" style={{
          position:'absolute',top:58,left:0,right:0,
          background:'rgba(10,9,8,0.99)',borderBottom:`1px solid ${BORDER}`,
          padding:'24px 5%',zIndex:99,
        }}>
          {[['menu','Cardápio'],['cart','Carrinho']].map(([p,l])=>(
            <button key={p} onClick={()=>go(p)} style={{
              display:'block',width:'100%',textAlign:'left',
              background:'transparent',border:'none',borderBottom:`1px solid ${BORDER}`,
              color:MUTED,fontSize:13,letterSpacing:'0.16em',textTransform:'uppercase',
              cursor:'pointer',fontFamily:SANS,padding:'16px 0',transition:'color .2s',
            }}
            onMouseEnter={e=>e.target.style.color=RED}
            onMouseLeave={e=>e.target.style.color=MUTED}
            >{l}</button>
          ))}
          {user
            ?<div style={{fontSize:12,color:GOLD,padding:'16px 0'}}>{user}</div>
            :<button onClick={()=>{setLoginOpen(true);setMenuOpen(false);}} style={{
              display:'block',width:'100%',textAlign:'left',
              background:'transparent',border:'none',
              color:MUTED,fontSize:13,letterSpacing:'0.16em',textTransform:'uppercase',
              cursor:'pointer',fontFamily:SANS,padding:'16px 0',
            }}>Entrar</button>
          }
        </div>
      )}
    </nav>
  );

  // ── CARD PRODUTO ──────────────────────────────────────────────────────────
  const ProdCard = ({p}) => (
    <div className="prod-card" style={{background:BG2,border:`1px solid ${BORDER}`,overflow:'hidden'}} onClick={()=>openTradicional(p)}>
      <div style={{height:isMobile?200:230,overflow:'hidden',position:'relative'}}>
        <img className="pimg" src={p.img} alt={p.name} style={{width:'100%',height:'100%',objectFit:'cover',display:'block',filter:'brightness(0.78)'}}/>
        {p.tag&&<div style={{position:'absolute',top:12,left:12,background:'rgba(10,9,8,0.88)',border:`1px solid rgba(196,30,36,.5)`,color:RED,fontSize:8,letterSpacing:'0.2em',padding:'4px 10px',textTransform:'uppercase',fontFamily:SANS}}>{p.tag}</div>}
      </div>
      <div style={{padding:isMobile?'18px 16px 20px':'22px 24px 26px'}}>
        <div style={{fontFamily:SERIF,fontSize:isMobile?19:20,color:CREAM,marginBottom:6}}>{p.name}</div>
        <div style={{fontSize:12,color:MUTED,lineHeight:1.7,marginBottom:16,fontWeight:300}}>{p.desc}</div>
        <div style={{display:'flex',justifyContent:'space-between',alignItems:'center'}}>
          <span style={{color:GOLD,fontSize:13}}>a partir de {R(p.prices.M)}</span>
          <span style={{fontSize:9,letterSpacing:'0.14em',color:MUTED,textTransform:'uppercase'}}>Pedir →</span>
        </div>
      </div>
    </div>
  );

  // ── CARD PERSONALIZADA ────────────────────────────────────────────────────
  const CardPersonalizada = () => (
    <div className="prod-card" style={{
      background:BG2,border:`1px solid rgba(196,30,36,.3)`,overflow:'hidden',
      display:'grid',gridTemplateColumns:isMobile?'1fr':'1fr 1fr',
    }} onClick={openPersonalizada}>
      <div style={{height:isMobile?200:'100%',minHeight:isMobile?0:260,overflow:'hidden',position:'relative'}}>
        <img className="pimg" src={PRODUTO_PERSONALIZADA.img} alt="Cheesecake Personalizada"
          style={{width:'100%',height:'100%',objectFit:'cover',display:'block',filter:'brightness(0.62)'}}/>
        <div style={{position:'absolute',inset:0,background:'linear-gradient(to right,rgba(196,30,36,0.1),transparent)'}}/>
        <div style={{position:'absolute',top:14,left:14,background:RED,color:CREAM,fontSize:8,letterSpacing:'0.2em',padding:'4px 12px',textTransform:'uppercase',fontFamily:SANS}}>Exclusivo</div>
      </div>
      <div style={{padding:isMobile?'24px 20px 28px':' 36px 32px',display:'flex',flexDirection:'column',justifyContent:'center'}}>
        <div style={{width:28,height:2,background:RED,marginBottom:16}}/>
        <div style={{...lbl,color:RED,fontSize:9,marginBottom:10}}>Monte do zero</div>
        <div style={{fontFamily:SERIF,fontSize:isMobile?24:28,color:CREAM,marginBottom:12,fontWeight:300,lineHeight:1.1}}>
          Cheesecake<br/><em style={{color:GOLD}}>Personalizada</em>
        </div>
        <p style={{fontSize:12,color:MUTED,lineHeight:1.8,fontWeight:300,marginBottom:24}}>
          Escolha base, creme e calda — e adicione extras à vontade. Feita exclusivamente do seu jeito.
        </p>
        <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',flexWrap:'wrap',gap:12}}>
          <span style={{color:GOLD,fontSize:13}}>a partir de {R(PRODUTO_PERSONALIZADA.prices.M)}</span>
          <BtnRed style={{fontSize:9,padding:'10px 18px'}}>Personalizar →</BtnRed>
        </div>
      </div>
    </div>
  );

  // ── MODAL INTERNO (layout unificado) ──────────────────────────────────────
  const ModalWrapper = ({children,onClose}) => (
    <div style={{
      position:'fixed',inset:0,background:'rgba(0,0,0,0.93)',zIndex:200,
      display:'flex',alignItems:isMobile?'flex-end':'flex-start',justifyContent:'center',
      padding:isMobile?0:'20px 16px',overflowY:isMobile?'hidden':'auto',
    }} onClick={e=>{if(e.target===e.currentTarget)onClose();}}>
      <div style={{
        background:BG2,
        border:isMobile?'none':`1px solid rgba(196,30,36,.25)`,
        borderTop:isMobile?`1px solid rgba(196,30,36,.3)`:'none',
        width:'100%',maxWidth:isMobile?'100%':560,
        padding:isMobile?'28px 20px 32px':40,
        marginTop:isMobile?0:20,
        maxHeight:isMobile?'92vh':'none',
        overflowY:'auto',
        borderRadius:0,
      }}>
        {/* Handle de drag no mobile */}
        {isMobile&&<div style={{width:36,height:3,background:'rgba(255,255,255,.15)',borderRadius:99,margin:'0 auto 20px'}}/>}
        {children}
      </div>
    </div>
  );

  return (
    <div style={{background:BG,minHeight:'100vh',color:CREAM,fontFamily:SANS}}>
      <style>{globalCSS}</style>
      <Nav/>

      {/* ════════════ HOME ══════════════════════════════════════════════════ */}
      {pg==='home'&&<>

        {/* HERO */}
        <section style={{position:'relative',height:isMobile?'100svh':'96vh',display:'flex',alignItems:'flex-end',overflow:'hidden'}}>
          <div className="hfade" style={{position:'absolute',inset:0,zIndex:0,backgroundImage:`url(${IMGS.hero})`,backgroundSize:'cover',backgroundPosition:'center 40%'}}/>
          <div style={{position:'absolute',inset:0,background:'linear-gradient(to top,rgba(10,9,8,1) 0%,rgba(10,9,8,0.65) 45%,rgba(10,9,8,.15) 100%)'}}/>
          <div style={{position:'absolute',inset:0,background:'linear-gradient(to right,rgba(10,9,8,0.5) 0%,transparent 70%)'}}/>

          {!isMobile&&<div style={{position:'absolute',left:'5%',top:'20%',bottom:'20%',width:1,background:`linear-gradient(to bottom,transparent,${RED} 30%,${RED} 70%,transparent)`,opacity:0.35}}/>}

          <div style={{position:'relative',zIndex:2,padding:isMobile?`0 6% 10vh`:`0 5% 7vh`,maxWidth:820}}>
            <div className="ha1" style={{...lbl,color:RED,marginBottom:isMobile?16:22,display:'flex',alignItems:'center',gap:12}}>
              <span style={{display:'inline-block',width:22,height:1,background:RED,opacity:.8}}/>
              Tatuapé · São Paulo · Artesanal
            </div>
            <h1 className="ha2" style={{
              fontFamily:SERIF,fontSize:isMobile?'clamp(42px,11vw,64px)':'clamp(52px,6.5vw,86px)',
              fontWeight:300,lineHeight:0.95,letterSpacing:'-0.01em',color:CREAM,
              marginBottom:isMobile?20:32,
            }}>
              O cheesecake<br/>que você<br/>
              <em style={{color:RED,fontWeight:300}}>não esquece.</em>
            </h1>
            <p className="ha3" style={{fontSize:isMobile?14:13,color:MUTED,lineHeight:1.85,maxWidth:400,fontWeight:300,marginBottom:isMobile?32:44}}>
              Produção artesanal, ingredientes selecionados e dedicação obsessiva pelo detalhe — do Tatuapé para a sua mesa.
            </p>
            <div className="ha4" style={{display:'flex',gap:12,alignItems:'center',flexWrap:'wrap'}}>
              <BtnRed onClick={()=>go('menu')} style={{padding:isMobile?'14px 28px':'13px 36px',fontSize:isMobile?11:10,width:isMobile?'100%':'auto',textAlign:'center'}}>
                Montar Meu Pedido
              </BtnRed>
              {!isMobile&&<a href="https://wa.me/5511933769243" target="_blank" rel="noreferrer" style={{color:MUTED,fontSize:10,letterSpacing:'0.18em',textTransform:'uppercase',fontFamily:SANS,transition:'color .2s'}} onMouseEnter={e=>e.target.style.color=RED} onMouseLeave={e=>e.target.style.color=MUTED}>WhatsApp →</a>}
            </div>
          </div>

          {/* Tag canal */}
          {!isMobile&&<div style={{position:'absolute',right:'5%',bottom:'8vh',borderLeft:`1px solid rgba(196,30,36,.35)`,paddingLeft:18}}>
            <div style={{...lbl,fontSize:8,color:RED,marginBottom:5}}>Disponível também em</div>
            <div style={{fontFamily:SERIF,fontSize:13,color:CREAM,fontWeight:300}}>iFood · Restaurantes Parceiros</div>
          </div>}

          {/* Mobile: CTA WhatsApp flutuante no hero */}
          {isMobile&&<div style={{position:'absolute',bottom:28,right:'6%',zIndex:3}}>
            <a href="https://wa.me/5511933769243" target="_blank" rel="noreferrer" style={{
              display:'flex',alignItems:'center',gap:8,
              background:'rgba(37,211,102,0.15)',border:'1px solid rgba(37,211,102,0.4)',
              color:'#25D366',padding:'9px 16px',fontSize:10,letterSpacing:'0.14em',textTransform:'uppercase',fontFamily:SANS,
            }}>
              <svg width="14" height="14" viewBox="0 0 24 24" fill="#25D366"><path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413z"/></svg>
              WhatsApp
            </a>
          </div>}
        </section>

        {/* DIFERENCIAIS */}
        <section style={{borderBottom:`1px solid ${BORDER}`}}>
          <div style={{display:'grid',gridTemplateColumns:isMobile?'1fr 1fr':'repeat(4,1fr)',gap:0}}>
            {DIFERENCIAIS.map((d,i)=>(
              <div key={i} className="diff-card" style={{
                padding:isMobile?'28px 18px':'44px 28px',
                borderRight:(isMobile?i%2===0:i<3)?`1px solid ${BORDER}`:'none',
                borderBottom:isMobile&&i<2?`1px solid ${BORDER}`:'none',
                borderTop:`1px solid ${BORDER}`,background:'transparent',
                transition:'all .25s',
              }}>
                <div style={{fontFamily:SERIF,fontSize:10,color:RED,letterSpacing:'0.2em',textTransform:'uppercase',marginBottom:10}}>{d.n}</div>
                <div style={{fontFamily:SERIF,fontSize:isMobile?15:17,color:CREAM,marginBottom:8}}>{d.t}</div>
                <div style={{fontSize:11,color:MUTED,lineHeight:1.7,fontWeight:300}}>{d.d}</div>
              </div>
            ))}
          </div>
        </section>

        {/* CARDÁPIO PREVIEW */}
        <section style={{padding:isMobile?'56px 5% 64px':'88px 5%'}}>
          <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-end',marginBottom:isMobile?36:56,flexWrap:'wrap',gap:16}}>
            <div>
              <div style={{...lbl,color:RED,marginBottom:12}} className="red-line">Nossos sabores</div>
              <h2 style={{fontFamily:SERIF,fontSize:isMobile?'clamp(28px,8vw,36px)':'clamp(30px,4vw,50px)',fontWeight:300,color:CREAM,lineHeight:1}}>
                O cardápio <em style={{color:GOLD}}>Badá</em>
              </h2>
            </div>
            {!isMobile&&<BtnOutline onClick={()=>go('menu')}>Ver cardápio completo →</BtnOutline>}
          </div>

          <div style={{display:'grid',gridTemplateColumns:isMobile?'1fr':'repeat(auto-fit,minmax(240px,1fr))',gap:1,background:BORDER}}>
            {PRODUCTS.map(p=><ProdCard key={p.id} p={p}/>)}
          </div>

          {isMobile&&<div style={{marginTop:20}}>
            <BtnOutline onClick={()=>go('menu')} style={{width:'100%',padding:'14px',textAlign:'center',display:'block'}}>Ver cardápio completo →</BtnOutline>
          </div>}
        </section>

        {/* SOBRE */}
        <section style={{padding:isMobile?'56px 5%':'88px 5%',borderTop:`1px solid ${BORDER}`,display:'grid',gridTemplateColumns:isMobile?'1fr':'1fr 1fr',gap:isMobile?40:72,alignItems:'center'}}>
          <div>
            <div style={{...lbl,color:RED,marginBottom:18}} className="red-line">A história por trás</div>
            <h2 style={{fontFamily:SERIF,fontSize:isMobile?'clamp(26px,7vw,36px)':'clamp(28px,3.5vw,44px)',fontWeight:300,color:CREAM,lineHeight:1.1,marginBottom:20}}>
              Feito por quem<br/><em style={{color:GOLD}}>ama o que faz.</em>
            </h2>
            <p style={{fontSize:13,color:MUTED,lineHeight:1.9,fontWeight:300,marginBottom:14}}>
              Gabriel Badaró — o Bada — começou fazendo cheesecakes para família e amigos no Tatuapé. O que era amor virou ofício, e o ofício virou uma confeitaria artesanal com identidade própria.
            </p>
            <p style={{fontSize:13,color:MUTED,lineHeight:1.9,fontWeight:300}}>
              Cada torta sai com a assinatura de quem se importa com cada camada — da massa à calda. Sem atalhos, sem fórmulas prontas.
            </p>
          </div>
          <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:1,background:`rgba(196,30,36,.2)`,aspectRatio:'1'}}>
            {[IMGS.galeria1,IMGS.galeria2,IMGS.galeria3,IMGS.galeria4].map((img,i)=>(
              <div key={i} style={{overflow:'hidden'}}>
                <img src={img} alt="" style={{width:'100%',height:'100%',objectFit:'cover',display:'block',filter:'brightness(0.65)',transition:'transform .4s'}}
                  onMouseEnter={e=>{if(!isMobile)e.target.style.transform='scale(1.07)'}}
                  onMouseLeave={e=>e.target.style.transform='scale(1)'}/>
              </div>
            ))}
          </div>
        </section>

        {/* REDES */}
        <section style={{padding:isMobile?'48px 5%':'64px 5%',borderTop:`1px solid ${BORDER}`,textAlign:'center'}}>
          <div style={{...lbl,color:RED,marginBottom:24}}>Siga, peça e avalie</div>
          <div style={{display:'flex',gap:10,justifyContent:'center',flexWrap:'wrap'}}>
            {SOCIALS.map(s2=>(
              <a key={s2.l} href={s2.u} target="_blank" rel="noreferrer" className="social-link" style={{
                border:`1px solid ${BORDER}`,color:MUTED,
                padding:isMobile?'11px 16px':'10px 20px',fontSize:10,letterSpacing:'0.14em',
                textTransform:'uppercase',fontFamily:SANS,display:'inline-block',transition:'all .2s',
              }}>{s2.l}</a>
            ))}
          </div>
        </section>
      </>}

      {/* ════════════ CARDÁPIO ══════════════════════════════════════════════ */}
      {pg==='menu'&&(
        <div style={{padding:isMobile?'48px 5% 80px':'80px 5% 96px'}}>
          <div style={{marginBottom:isMobile?36:52}}>
            <div style={{...lbl,color:RED,marginBottom:12}} className="red-line">Escolha e personalize</div>
            <h2 style={{fontFamily:SERIF,fontSize:isMobile?'clamp(28px,8vw,38px)':'clamp(30px,4vw,50px)',fontWeight:300,color:CREAM}}>
              Cardápio <em style={{color:GOLD}}>completo</em>
            </h2>
          </div>

          <div style={{marginBottom:1}}><CardPersonalizada/></div>

          <div style={{display:'grid',gridTemplateColumns:isMobile?'1fr':'repeat(auto-fit,minmax(260px,1fr))',gap:1,background:BORDER}}>
            {PRODUCTS.map(p=>(
              <div key={p.id} className="prod-card" style={{background:BG2,overflow:'hidden'}} onClick={()=>openTradicional(p)}>
                <div style={{height:isMobile?200:240,overflow:'hidden',position:'relative'}}>
                  <img className="pimg" src={p.img} alt={p.name} style={{width:'100%',height:'100%',objectFit:'cover',display:'block',filter:'brightness(0.78)'}}/>
                  {p.tag&&<div style={{position:'absolute',top:12,left:12,background:'rgba(10,9,8,0.88)',border:`1px solid rgba(196,30,36,.5)`,color:RED,fontSize:8,letterSpacing:'0.2em',padding:'4px 10px',textTransform:'uppercase'}}>{p.tag}</div>}
                </div>
                <div style={{padding:isMobile?'18px 16px 22px':'24px 24px 28px'}}>
                  <div style={{fontFamily:SERIF,fontSize:isMobile?20:22,color:CREAM,marginBottom:7}}>{p.name}</div>
                  <div style={{fontSize:12,color:MUTED,lineHeight:1.75,marginBottom:18,fontWeight:300}}>{p.desc}</div>
                  <div style={{display:'grid',gridTemplateColumns:p.sizesInfo?'1fr 1fr 1fr':'1fr 1fr',gap:8,marginBottom:18}}>
                    {p.sizesInfo
                      ? Object.entries(p.sizesInfo).map(([sz,info])=>(
                          <div key={sz} style={{background:BG3,padding:'12px',textAlign:'center',border:'1px solid rgba(255,255,255,.04)'}}>
                            <div style={{...lbl,fontSize:7,marginBottom:4}}>{info.label}</div>
                            <div style={{fontSize:9,color:MUTED,marginBottom:6,fontFamily:SANS}}>{info.sub}</div>
                            <div style={{fontFamily:SERIF,fontSize:16,color:CREAM}}>{p.prices[sz]>0?R(p.prices[sz]):'A definir'}</div>
                          </div>
                        ))
                      : [['M','Médio','8 fatias'],['G','Grande','12 fatias']].map(([sz,l2,s2])=>(
                          <div key={sz} style={{background:BG3,padding:'12px',textAlign:'center',border:'1px solid rgba(255,255,255,.04)'}}>
                            <div style={{...lbl,fontSize:8,marginBottom:5}}>{l2} · {s2}</div>
                            <div style={{fontFamily:SERIF,fontSize:18,color:CREAM}}>{R(p.prices[sz])}</div>
                          </div>
                        ))
                    }
                  </div>
                  <BtnRed style={{width:'100%',padding:'13px',textAlign:'center',display:'block',fontSize:isMobile?11:10}}>
                    Pedir este sabor
                  </BtnRed>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* ════════════ CARRINHO ══════════════════════════════════════════════ */}
      {pg==='cart'&&(
        <div style={{padding:isMobile?'40px 5% 100px':'80px 5% 96px',maxWidth:1040,margin:'0 auto'}}>
          <div style={{marginBottom:isMobile?32:52}}>
            <div style={{...lbl,color:RED,marginBottom:12}} className="red-line">Meu pedido</div>
            <h2 style={{fontFamily:SERIF,fontSize:isMobile?'clamp(28px,8vw,38px)':'clamp(30px,4vw,50px)',fontWeight:300,color:CREAM}}>
              Revisar <em style={{color:GOLD}}>carrinho</em>
            </h2>
          </div>

          {cart.length===0?(
            <div style={{textAlign:'center',padding:'72px 0'}}>
              <div style={{fontFamily:SERIF,fontSize:22,color:MUTED,marginBottom:8,fontStyle:'italic'}}>Nada aqui ainda</div>
              <div style={{fontSize:12,color:MUTED,marginBottom:32,opacity:.6}}>Seu carrinho está vazio</div>
              <BtnRed onClick={()=>go('menu')}>Ver Cardápio</BtnRed>
            </div>
          ):(
            <div style={{display:'grid',gridTemplateColumns:isMobile?'1fr':'1fr 300px',gap:isMobile?0:32,alignItems:'start'}}>
              <div>
                {cart.map(item=>(
                  <div key={item.id} style={{background:BG2,border:`1px solid ${BORDER}`,padding:isMobile?'16px':24,marginBottom:12,display:'flex',justifyContent:'space-between',gap:14,alignItems:'flex-start'}}>
                    <div style={{flex:1}}>
                      <div style={{display:'flex',alignItems:'center',gap:8,marginBottom:5,flexWrap:'wrap'}}>
                        <div style={{fontFamily:SERIF,fontSize:isMobile?17:19,color:CREAM}}>{item.name}</div>
                        {item.tipo==='personalizada'&&<span style={{fontSize:8,letterSpacing:'0.14em',border:`1px solid rgba(196,30,36,.4)`,color:RED,padding:'2px 7px',textTransform:'uppercase'}}>Custom</span>}
                      </div>
                      <div style={{...lbl,fontSize:8,color:RED,marginBottom:8}}>
                        {item.sz==='M'?'Médio · 8 fatias':'Grande · 12 fatias'} · Qtd: {item.qty}
                      </div>
                      <div style={{fontSize:11,color:MUTED,lineHeight:1.8}}>
                        {item.tipo==='personalizada'&&<>Base: {item.base}<br/>Creme: {item.creme}<br/>Calda: {item.calda}<br/></>}
                        {item.dobroCreme&&<span style={{color:RED}}>Dobro de creme ativado<br/></span>}
                        {item.extras?.length>0&&<span style={{color:GOLD}}>Caldas extras: {item.extras.join(', ')}<br/></span>}
                        {item.toppings?.length>0&&<span style={{color:GOLD}}>Toppings: {item.toppings.map(id=>TOPPINGS.find(t=>t.id===id)?.nome).join(', ')}</span>}
                      </div>
                    </div>
                    <div style={{textAlign:'right',flexShrink:0}}>
                      <div style={{fontFamily:SERIF,fontSize:isMobile?20:24,color:GOLD,marginBottom:8}}>{R(item.total)}</div>
                      <button onClick={()=>setCart(c=>c.filter(i=>i.id!==item.id))} style={{
                        background:'transparent',border:`1px solid rgba(196,30,36,.18)`,
                        color:'rgba(196,30,36,.6)',fontSize:9,padding:'5px 10px',
                        cursor:'pointer',fontFamily:SANS,letterSpacing:'0.1em',textTransform:'uppercase',transition:'all .2s',
                      }}
                      onMouseEnter={e=>{e.target.style.borderColor='rgba(196,30,36,.5)';e.target.style.color=RED;}}
                      onMouseLeave={e=>{e.target.style.borderColor='rgba(196,30,36,.18)';e.target.style.color='rgba(196,30,36,.6)';}}
                      >Remover</button>
                    </div>
                  </div>
                ))}

                {/* Recebimento */}
                <div style={{background:BG2,border:`1px solid ${BORDER}`,padding:isMobile?16:24,marginBottom:12}}>
                  <div style={{...lbl,marginBottom:16}}>Forma de recebimento</div>
                  <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:10,marginBottom:16}}>
                    {[['pickup','Retirada · Grátis'],['delivery','Entrega · Até 15 km']].map(([v,l2])=>(
                      <button key={v} onClick={()=>setDlv(v)} style={{
                        padding:isMobile?14:13,background:dlv===v?'rgba(196,30,36,.08)':BG3,
                        border:`1px solid ${dlv===v?RED:'rgba(255,255,255,.06)'}`,
                        color:dlv===v?RED:MUTED,cursor:'pointer',fontSize:isMobile?12:10,letterSpacing:'0.12em',
                        fontFamily:SANS,textTransform:'uppercase',transition:'all .2s',
                      }}>{l2}</button>
                    ))}
                  </div>
                  {dlv==='pickup'&&<div style={{fontSize:12,color:MUTED,lineHeight:1.9}}>Rua Emilio Mallet, 95 · Tatuapé · São Paulo – SP</div>}
                  {dlv==='delivery'&&<div>
                    <label style={{...lbl,fontSize:9,display:'block',marginBottom:10}}>Endereço completo</label>
                    <input style={inp} placeholder="Rua, número, bairro — São Paulo" value={addr} onChange={e=>setAddr(e.target.value)}/>
                    {addr.length>=5&&frete&&(frete.err
                      ?<div style={{fontSize:12,color:RED,marginTop:10}}>Endereço fora do raio de 15 km. Tente retirada ou fale pelo WhatsApp.</div>
                      :<div style={{fontSize:12,color:GOLD,marginTop:10}}>~{frete.km} km · Frete: {R(frete.fee)}</div>
                    )}
                  </div>}
                </div>

                {/* Data */}
                <div style={{background:BG2,border:`1px solid ${BORDER}`,padding:isMobile?16:24,marginBottom:12}}>
                  <div style={{...lbl,marginBottom:8}}>Data de entrega ou retirada</div>
                  <div style={{fontSize:12,color:MUTED,marginBottom:16,fontWeight:300}}>Disponível a partir de 2 dias úteis</div>
                  <div style={{display:'flex',flexWrap:'wrap',gap:8}}>
                    {dates.map((d,i)=>(
                      <button key={i} onClick={()=>setSelDate(d)} style={{
                        padding:isMobile?'11px 14px':'9px 13px',
                        background:selDate===d?'rgba(196,30,36,.1)':BG3,
                        border:`1px solid ${selDate===d?RED:'rgba(255,255,255,.06)'}`,
                        color:selDate===d?RED:MUTED,
                        cursor:'pointer',fontSize:isMobile?12:11,fontFamily:SANS,transition:'all .2s',
                      }}>{fmt(d)}</button>
                    ))}
                  </div>
                  {selDate&&<div style={{fontSize:12,color:RED,marginTop:14}}>✓ {selDate.toLocaleDateString('pt-BR',{weekday:'long',day:'2-digit',month:'long',year:'numeric'})}</div>}
                </div>

                {/* Resumo mobile — inline */}
                {isMobile&&(
                  <div style={{background:BG2,border:`1px solid rgba(201,169,110,.18)`,padding:20,marginBottom:12}}>
                    <div style={{...lbl,marginBottom:16}}>Resumo do pedido</div>
                    <div style={{display:'flex',justifyContent:'space-between',fontSize:13,color:MUTED,marginBottom:8}}><span>Subtotal</span><span>{R(sub)}</span></div>
                    {dlv==='delivery'&&<div style={{display:'flex',justifyContent:'space-between',fontSize:13,color:MUTED,marginBottom:8}}><span>Frete</span><span>{frete?.fee!=null&&!frete.err?R(frete.fee):'—'}</span></div>}
                    <div style={{borderTop:`1px solid ${BORDER}`,paddingTop:14,marginBottom:20,display:'flex',justifyContent:'space-between',alignItems:'baseline'}}>
                      <span style={{fontFamily:SERIF,fontSize:18,color:CREAM}}>Total</span>
                      <span style={{fontFamily:SERIF,fontSize:24,color:GOLD}}>{R(dlv==='delivery'&&frete?.fee?total:sub)}</span>
                    </div>
                    <BtnRed disabled={!canPay} style={{width:'100%',padding:'15px',textAlign:'center',display:'block',fontSize:12}}
                      onClick={()=>{if(!canPay)return;if(!user)setLoginOpen(true);else go('checkout');}}>
                      {!user?'Entrar e Finalizar':'Ir para Pagamento'}
                    </BtnRed>
                    {!selDate&&<div style={{fontSize:11,color:MUTED,textAlign:'center',marginTop:10,opacity:.5}}>Selecione uma data para continuar</div>}
                    <BtnOutline onClick={()=>go('menu')} style={{width:'100%',marginTop:10,padding:'13px',textAlign:'center',display:'block',fontSize:11}}>
                      + Adicionar mais itens
                    </BtnOutline>
                  </div>
                )}
              </div>

              {/* Resumo desktop — sticky */}
              {!isMobile&&(
                <div style={{position:'sticky',top:80}}>
                  <div style={{background:BG2,border:`1px solid rgba(201,169,110,.18)`,padding:24}}>
                    <div style={{...lbl,marginBottom:20}}>Resumo do pedido</div>
                    <div style={{display:'flex',justifyContent:'space-between',fontSize:12,color:MUTED,marginBottom:10}}><span>Subtotal</span><span>{R(sub)}</span></div>
                    {dlv==='delivery'&&<div style={{display:'flex',justifyContent:'space-between',fontSize:12,color:MUTED,marginBottom:10}}><span>Frete</span><span>{frete?.fee!=null&&!frete.err?R(frete.fee):'—'}</span></div>}
                    <div style={{borderTop:`1px solid ${BORDER}`,paddingTop:18,marginBottom:24,display:'flex',justifyContent:'space-between',alignItems:'baseline'}}>
                      <span style={{fontFamily:SERIF,fontSize:18,color:CREAM}}>Total</span>
                      <span style={{fontFamily:SERIF,fontSize:26,color:GOLD}}>{R(dlv==='delivery'&&frete?.fee?total:sub)}</span>
                    </div>
                    <BtnRed disabled={!canPay} style={{width:'100%',padding:'14px',textAlign:'center',display:'block'}}
                      onClick={()=>{if(!canPay)return;if(!user)setLoginOpen(true);else go('checkout');}}>
                      {!user?'Entrar e Finalizar':'Ir para Pagamento'}
                    </BtnRed>
                    {!selDate&&<div style={{fontSize:10,color:MUTED,textAlign:'center',marginTop:10,opacity:.5}}>Selecione uma data para continuar</div>}
                    <BtnOutline onClick={()=>go('menu')} style={{width:'100%',marginTop:10,padding:'12px',textAlign:'center',display:'block'}}>
                      + Adicionar mais itens
                    </BtnOutline>
                  </div>
                </div>
              )}
            </div>
          )}
        </div>
      )}

      {/* ════════════ CHECKOUT ══════════════════════════════════════════════ */}
      {pg==='checkout'&&(
        <div style={{padding:isMobile?'40px 5% 100px':'80px 5% 96px',maxWidth:680,margin:'0 auto'}}>
          <div style={{marginBottom:isMobile?32:52}}>
            <div style={{...lbl,color:RED,marginBottom:12}} className="red-line">Finalizar pedido</div>
            <h2 style={{fontFamily:SERIF,fontSize:isMobile?'clamp(28px,8vw,38px)':'clamp(30px,4vw,50px)',fontWeight:300,color:CREAM}}>
              Forma de <em style={{color:GOLD}}>pagamento</em>
            </h2>
          </div>

          <div style={{background:BG2,border:`1px solid rgba(201,169,110,.2)`,padding:isMobile?16:24,marginBottom:24,display:'flex',justifyContent:'space-between',alignItems:'center',flexWrap:'wrap',gap:16}}>
            <div>
              <div style={{fontSize:12,color:MUTED,marginBottom:5}}>{dlv==='pickup'?'Retirada: Rua Emilio Mallet, 95 · Tatuapé':'Entrega: '+addr}</div>
              <div style={{fontSize:13,color:RED,marginBottom:4}}>{selDate?.toLocaleDateString('pt-BR',{weekday:'long',day:'2-digit',month:'long'})}</div>
              <div style={{fontSize:11,color:MUTED,opacity:.6}}>{cart.length} {cart.length===1?'item':'itens'} · {user}</div>
            </div>
            <div style={{fontFamily:SERIF,fontSize:isMobile?26:32,color:GOLD}}>{R(total)}</div>
          </div>

          {/* Informativo sobre formas de pagamento */}
          <div style={{background:BG2,border:`1px solid ${BORDER}`,padding:isMobile?16:24,marginBottom:20}}>
            <div style={{...lbl,marginBottom:16}}>Formas de pagamento aceitas</div>
            <div style={{display:'flex',gap:10,flexWrap:'wrap',marginBottom:8}}>
              {['PIX','Cartão de Crédito','Cartão de Débito','Boleto'].map(m=>(
                <span key={m} style={{
                  fontSize:10,color:GOLD,padding:'5px 12px',
                  border:`1px solid rgba(201,169,110,.25)`,
                  background:'rgba(201,169,110,.05)',
                  fontFamily:SANS,letterSpacing:'0.1em',
                }}>{m}</span>
              ))}
            </div>
            <p style={{fontSize:11,color:MUTED,lineHeight:1.8,fontWeight:300}}>
              Você será redirecionado para o ambiente seguro do Mercado Pago para concluir o pagamento. PIX com aprovação instantânea.
            </p>
          </div>

          {mpError && (
            <div style={{fontSize:12,color:RED,marginBottom:12,padding:'10px 14px',border:`1px solid rgba(196,30,36,.3)`,background:'rgba(196,30,36,.05)'}}>
              {mpError}
            </div>
          )}
          <BtnRed
            disabled={mpLoading}
            style={{width:'100%',padding:'16px',textAlign:'center',display:'block',fontSize:12,letterSpacing:'0.2em',marginBottom:12}}
            onClick={handleMPCheckout}>
            {mpLoading ? 'Aguarde...' : 'Pagar com Mercado Pago'}
          </BtnRed>
          <a href="https://wa.me/5511933769243" target="_blank" rel="noreferrer" style={{
            display:'block',width:'100%',padding:'14px',textAlign:'center',
            border:`1px solid rgba(37,211,102,.35)`,color:'#25D366',
            fontSize:11,letterSpacing:'0.16em',textTransform:'uppercase',
            fontFamily:SANS,marginBottom:12,transition:'all .2s',
          }}
          onMouseEnter={e=>{e.currentTarget.style.borderColor='#25D366';e.currentTarget.style.background='rgba(37,211,102,.08)';}}
          onMouseLeave={e=>{e.currentTarget.style.borderColor='rgba(37,211,102,.35)';e.currentTarget.style.background='transparent';}}
          >Ou finalize pelo WhatsApp</a>
          <BtnOutline onClick={()=>go('cart')} style={{width:'100%',padding:'13px',textAlign:'center',display:'block'}}>
            ← Voltar ao carrinho
          </BtnOutline>
        </div>
      )}

      {/* ════════════ CONFIRMAÇÃO ═══════════════════════════════════════════ */}
      {pg==='confirmation'&&(
        <div style={{padding:isMobile?'80px 5% 100px':'120px 5%',textAlign:'center',maxWidth:600,margin:'0 auto'}}>
          <div style={{width:72,height:72,borderRadius:'50%',border:`1px solid ${RED}`,display:'flex',alignItems:'center',justifyContent:'center',margin:'0 auto 36px',color:RED,fontSize:26}}>✓</div>
          <div style={{...lbl,color:RED,marginBottom:14}}>Pedido confirmado</div>
          <h2 style={{fontFamily:SERIF,fontSize:isMobile?'clamp(28px,8vw,38px)':'clamp(30px,4vw,50px)',fontWeight:300,color:CREAM,marginBottom:20}}>
            Obrigado pelo<br/><em style={{color:GOLD}}>seu pedido.</em>
          </h2>
          <p style={{fontSize:13,color:MUTED,lineHeight:1.9,marginBottom:44,fontWeight:300}}>
            Em breve entraremos em contato pelo WhatsApp para confirmar os detalhes. Prepara a faca — uma fatia incrível está a caminho.
          </p>
          <div style={{display:'flex',gap:12,justifyContent:'center',flexWrap:'wrap'}}>
            <BtnRed onClick={()=>go('home')} style={isMobile?{flex:1,textAlign:'center'}:{}}>Voltar ao início</BtnRed>
            <a href="https://wa.me/5511933769243" target="_blank" rel="noreferrer" style={{
              border:`1px solid ${BORDER}`,color:MUTED,
              padding:'13px 24px',fontSize:10,letterSpacing:'0.18em',
              textTransform:'uppercase',fontFamily:SANS,transition:'all .2s',display:'inline-block',
              ...(isMobile?{flex:1,textAlign:'center'}:{}),
            }}
            onMouseEnter={e=>{e.currentTarget.style.borderColor=RED;e.currentTarget.style.color=RED;}}
            onMouseLeave={e=>{e.currentTarget.style.borderColor=BORDER;e.currentTarget.style.color=MUTED;}}
            >Falar no WhatsApp</a>
          </div>
        </div>
      )}

      {/* ════════════ MODAL — TRADICIONAL ════════════════════════════════════ */}
      {modal&&modal.modo==='tradicional'&&(
        <ModalWrapper onClose={()=>setModal(null)}>
          <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:28}}>
            <div>
              <div style={{width:22,height:2,background:RED,marginBottom:12}}/>
              <div style={{...lbl,fontSize:9,color:RED,marginBottom:8}}>Sabor Tradicional</div>
              <h3 style={{fontFamily:SERIF,fontSize:isMobile?24:28,fontWeight:300,color:CREAM}}>{modal.produto.name}</h3>
            </div>
            <button onClick={()=>setModal(null)} style={{background:'transparent',border:`1px solid ${BORDER}`,color:MUTED,width:36,height:36,cursor:'pointer',fontSize:16,display:'flex',alignItems:'center',justifyContent:'center',transition:'all .2s',flexShrink:0}}
              onMouseEnter={e=>{e.currentTarget.style.borderColor=RED;e.currentTarget.style.color=RED;}}
              onMouseLeave={e=>{e.currentTarget.style.borderColor=BORDER;e.currentTarget.style.color=MUTED;}}
            >✕</button>
          </div>

          <p style={{fontSize:12,color:MUTED,lineHeight:1.8,marginBottom:24,fontWeight:300}}>{modal.produto.desc}</p>

          <div style={{marginBottom:22}}>
            <div style={{...lbl,fontSize:9,marginBottom:12}}>Tamanho</div>
            <div style={{display:'grid',gridTemplateColumns:modal.produto.sizesInfo?'1fr':'1fr 1fr',gap:10}}>
              {modal.produto.sizesInfo
                ? Object.entries(modal.produto.sizesInfo).map(([v,info])=>(
                    <button key={v} onClick={()=>setCust(c=>({...c,sz:v}))} style={{
                      padding:isMobile?14:16,textAlign:'left',cursor:'pointer',
                      background:cust.sz===v?'rgba(196,30,36,.07)':BG3,
                      border:'1px solid '+(cust.sz===v?RED:'rgba(255,255,255,.06)'),
                      color:cust.sz===v?RED:CREAM,transition:'all .2s',
                      display:'flex',justifyContent:'space-between',alignItems:'center',
                    }}>
                      <div>
                        <div style={{fontSize:9,letterSpacing:'0.12em',textTransform:'uppercase',marginBottom:5,fontFamily:SANS,color:MUTED}}>{info.sub}</div>
                        <div style={{fontFamily:SERIF,fontSize:isMobile?17:19}}>{info.label}</div>
                      </div>
                      <div style={{fontFamily:SERIF,fontSize:isMobile?18:20,color:GOLD,flexShrink:0,marginLeft:12}}>
                        {modal.produto.prices[v]>0?R(modal.produto.prices[v]):'A definir'}
                      </div>
                    </button>
                  ))
                : [['M','Médio','8 fatias'],['G','Grande','12 fatias']].map(([v,l2,s2])=>(
                    <button key={v} onClick={()=>setCust(c=>({...c,sz:v}))} style={{
                      padding:isMobile?16:18,textAlign:'left',cursor:'pointer',
                      background:cust.sz===v?'rgba(196,30,36,.07)':BG3,
                      border:'1px solid '+(cust.sz===v?RED:'rgba(255,255,255,.06)'),
                      color:cust.sz===v?RED:CREAM,transition:'all .2s',
                    }}>
                      <div style={{fontSize:9,letterSpacing:'0.12em',textTransform:'uppercase',marginBottom:6,fontFamily:SANS,color:MUTED}}>{l2} · {s2}</div>
                      <div style={{fontFamily:SERIF,fontSize:isMobile?20:22}}>{R(modal.produto.prices[v])}</div>
                    </button>
                  ))
              }
            </div>
          </div>

          <DobroCreme checked={cust.dobroCreme} onChange={()=>setCust(c=>({...c,dobroCreme:!c.dobroCreme}))} isNinho={modal.produto.id===6}/>

          <div style={{marginBottom:22}}>
            <div style={{...lbl,fontSize:9,marginBottom:12}}>
              Calda extra <span style={{color:MUTED,opacity:.7,letterSpacing:0}}>(+{R(EXTRA_PRICE)} cada)</span>
            </div>
            <div style={{display:'flex',flexWrap:'wrap',gap:8}}>
              {CALDAS.map(c=>(
                <button key={c} onClick={()=>toggleExtra(c)} style={{
                  padding:isMobile?'10px 14px':'7px 14px',cursor:'pointer',
                  background:cust.extras.includes(c)?'rgba(196,30,36,.1)':BG3,
                  border:`1px solid ${cust.extras.includes(c)?RED:'rgba(255,255,255,.06)'}`,
                  color:cust.extras.includes(c)?RED:MUTED,
                  fontSize:isMobile?13:11,fontFamily:SANS,transition:'all .2s',
                }}>{c}</button>
              ))}
            </div>
          </div>

          <ToppingsPanel selected={cust.toppings} onToggle={toggleTopping} isMobile={isMobile}/>

          <div style={{display:'flex',alignItems:'center',gap:16,marginBottom:28}}>
            <div style={{...lbl,fontSize:9}}>Quantidade</div>
            <div style={{display:'flex',alignItems:'center',border:`1px solid ${BORDER}`}}>
              {[['−',()=>setCust(c=>({...c,qty:Math.max(1,c.qty-1)}))],['+',()=>setCust(c=>({...c,qty:c.qty+1}))]].map(([sym,fn],idx)=>(
                <button key={idx} onClick={fn} style={{
                  width:isMobile?44:40,height:isMobile?44:40,background:'transparent',border:'none',
                  borderRight:idx===0?`1px solid ${BORDER}`:'none',
                  borderLeft:idx===1?`1px solid ${BORDER}`:'none',
                  color:MUTED,cursor:'pointer',fontSize:20,transition:'all .2s',
                }}
                onMouseEnter={e=>{e.target.style.color=RED;e.target.style.background=BG3;}}
                onMouseLeave={e=>{e.target.style.color=MUTED;e.target.style.background='transparent';}}
                >{sym}</button>
              ))}
              <span style={{width:isMobile?48:44,textAlign:'center',fontFamily:SERIF,fontSize:20,color:CREAM}}>{cust.qty}</span>
            </div>
          </div>

          <div style={{borderTop:`1px solid ${BORDER}`,paddingTop:20,display:'flex',justifyContent:'space-between',alignItems:'center',gap:16,flexWrap:isMobile?'wrap':'nowrap'}}>
            <div>
              <div style={{fontSize:10,color:MUTED,marginBottom:4,opacity:.6}}>Total do item</div>
              <div style={{fontFamily:SERIF,fontSize:isMobile?28:32,color:GOLD}}>{R(itemPrice())}</div>
            </div>
            <BtnRed onClick={addToCart} style={{padding:'14px 28px',width:isMobile?'100%':'auto',textAlign:'center'}}>Adicionar ao Carrinho</BtnRed>
          </div>
        </ModalWrapper>
      )}

      {/* ════════════ MODAL — PERSONALIZADA ════════════════════════════════════ */}
      {modal&&modal.modo==='personalizada'&&(
        <ModalWrapper onClose={()=>setModal(null)}>
          <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:28}}>
            <div>
              <div style={{width:22,height:2,background:RED,marginBottom:12}}/>
              <div style={{...lbl,fontSize:9,color:RED,marginBottom:8}}>Monte do zero</div>
              <h3 style={{fontFamily:SERIF,fontSize:isMobile?24:28,fontWeight:300,color:CREAM}}>
                Cheesecake <em style={{color:GOLD}}>Personalizada</em>
              </h3>
            </div>
            <button onClick={()=>setModal(null)} style={{background:'transparent',border:`1px solid ${BORDER}`,color:MUTED,width:36,height:36,cursor:'pointer',fontSize:16,display:'flex',alignItems:'center',justifyContent:'center',transition:'all .2s',flexShrink:0}}
              onMouseEnter={e=>{e.currentTarget.style.borderColor=RED;e.currentTarget.style.color=RED;}}
              onMouseLeave={e=>{e.currentTarget.style.borderColor=BORDER;e.currentTarget.style.color=MUTED;}}
            >✕</button>
          </div>

          <div style={{marginBottom:22}}>
            <div style={{...lbl,fontSize:9,marginBottom:12}}>Tamanho</div>
            <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:10}}>
              {[['M','Médio','8 fatias'],['G','Grande','12 fatias']].map(([v,l2,s2])=>(
                <button key={v} onClick={()=>setCust(c=>({...c,sz:v}))} style={{
                  padding:isMobile?16:18,textAlign:'left',cursor:'pointer',
                  background:cust.sz===v?'rgba(196,30,36,.07)':BG3,
                  border:`1px solid ${cust.sz===v?RED:'rgba(255,255,255,.06)'}`,
                  color:cust.sz===v?RED:CREAM,transition:'all .2s',
                }}>
                  <div style={{fontSize:9,letterSpacing:'0.12em',textTransform:'uppercase',marginBottom:6,fontFamily:SANS,color:MUTED}}>{l2} · {s2}</div>
                  <div style={{fontFamily:SERIF,fontSize:isMobile?20:22}}>{R(PRODUTO_PERSONALIZADA.prices[v])}</div>
                </button>
              ))}
            </div>
          </div>

          <DobroCreme checked={cust.dobroCreme} onChange={()=>setCust(c=>({...c,dobroCreme:!c.dobroCreme}))} isNinho={false}/>

          {[['base','Base da massa',BASES],['creme','Creme',CREMES],['calda','Calda principal',CALDAS]].map(([k,l2,opts])=>(
            <div key={k} style={{marginBottom:16}}>
              <label style={{...lbl,fontSize:9,display:'block',marginBottom:9}}>{l2}</label>
              <select style={{...inp,cursor:'pointer',fontSize:isMobile?15:13}} value={cust[k]} onChange={e=>setCust(c=>({...c,[k]:e.target.value}))}>
                {opts.map(o=><option key={o} value={o}>{o}</option>)}
              </select>
            </div>
          ))}

          <div style={{marginBottom:22}}>
            <div style={{...lbl,fontSize:9,marginBottom:12}}>
              Caldas extras <span style={{color:MUTED,opacity:.7,letterSpacing:0}}>(+{R(EXTRA_PRICE)} cada)</span>
            </div>
            <div style={{display:'flex',flexWrap:'wrap',gap:8}}>
              {CALDAS.map(c=>(
                <button key={c} onClick={()=>toggleExtra(c)} style={{
                  padding:isMobile?'10px 14px':'7px 14px',cursor:'pointer',
                  background:cust.extras.includes(c)?'rgba(196,30,36,.1)':BG3,
                  border:`1px solid ${cust.extras.includes(c)?RED:'rgba(255,255,255,.06)'}`,
                  color:cust.extras.includes(c)?RED:MUTED,
                  fontSize:isMobile?13:11,fontFamily:SANS,transition:'all .2s',
                }}>{c}</button>
              ))}
            </div>
          </div>

          <ToppingsPanel selected={cust.toppings} onToggle={toggleTopping} isMobile={isMobile}/>

          <div style={{display:'flex',alignItems:'center',gap:16,marginBottom:28}}>
            <div style={{...lbl,fontSize:9}}>Quantidade</div>
            <div style={{display:'flex',alignItems:'center',border:`1px solid ${BORDER}`}}>
              {[['−',()=>setCust(c=>({...c,qty:Math.max(1,c.qty-1)}))],['+',()=>setCust(c=>({...c,qty:c.qty+1}))]].map(([sym,fn],idx)=>(
                <button key={idx} onClick={fn} style={{
                  width:isMobile?44:40,height:isMobile?44:40,background:'transparent',border:'none',
                  borderRight:idx===0?`1px solid ${BORDER}`:'none',
                  borderLeft:idx===1?`1px solid ${BORDER}`:'none',
                  color:MUTED,cursor:'pointer',fontSize:20,transition:'all .2s',
                }}
                onMouseEnter={e=>{e.target.style.color=RED;e.target.style.background=BG3;}}
                onMouseLeave={e=>{e.target.style.color=MUTED;e.target.style.background='transparent';}}
                >{sym}</button>
              ))}
              <span style={{width:isMobile?48:44,textAlign:'center',fontFamily:SERIF,fontSize:20,color:CREAM}}>{cust.qty}</span>
            </div>
          </div>

          <div style={{borderTop:`1px solid ${BORDER}`,paddingTop:20,display:'flex',justifyContent:'space-between',alignItems:'center',gap:16,flexWrap:isMobile?'wrap':'nowrap'}}>
            <div>
              <div style={{fontSize:10,color:MUTED,marginBottom:4,opacity:.6}}>Total do item</div>
              <div style={{fontFamily:SERIF,fontSize:isMobile?28:32,color:GOLD}}>{R(itemPrice())}</div>
            </div>
            <BtnRed onClick={addToCart} style={{padding:'14px 28px',width:isMobile?'100%':'auto',textAlign:'center'}}>Adicionar ao Carrinho</BtnRed>
          </div>
        </ModalWrapper>
      )}

      {/* ════════════ MODAL — LOGIN ════════════════════════════════════════════ */}
      {loginOpen&&(
        <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.93)',zIndex:200,display:'flex',alignItems:isMobile?'flex-end':'center',justifyContent:'center',padding:isMobile?0:16}}
          onClick={e=>{if(e.target===e.currentTarget)setLoginOpen(false);}}>
          <div style={{
            background:BG2,border:`1px solid rgba(196,30,36,.25)`,
            borderTop:isMobile?`1px solid rgba(196,30,36,.3)`:'none',
            maxWidth:isMobile?'100%':360,width:'100%',
            padding:isMobile?'32px 24px 40px':48,
            textAlign:'center',position:'relative',
          }}>
            {isMobile&&<div style={{width:36,height:3,background:'rgba(255,255,255,.15)',borderRadius:99,margin:'0 auto 24px'}}/>}
            <button onClick={()=>setLoginOpen(false)} style={{position:'absolute',top:16,right:16,background:'transparent',border:`1px solid ${BORDER}`,color:MUTED,width:32,height:32,cursor:'pointer',fontSize:14,display:'flex',alignItems:'center',justifyContent:'center',transition:'all .2s'}}
              onMouseEnter={e=>{e.currentTarget.style.borderColor=RED;e.currentTarget.style.color=RED;}}
              onMouseLeave={e=>{e.currentTarget.style.borderColor=BORDER;e.currentTarget.style.color=MUTED;}}
            >✕</button>
            <div style={{margin:'0 auto 24px',display:'flex',justifyContent:'center'}}>
              <LogoBada height={isMobile?120:180}/>
            </div>
            <div style={{...lbl,fontSize:9,color:RED,marginBottom:12}}>Acesse sua conta</div>
            <h3 style={{fontFamily:SERIF,fontSize:isMobile?26:28,fontWeight:300,color:CREAM,marginBottom:32}}>
              Entrar na <em style={{color:GOLD}}>Badá</em>
            </h3>
            {[{label:'Continuar com Google',bg:'#fff',color:'#111'},{label:'Continuar com Apple',bg:'#000',color:'#fff'}].map(btn=>(
              <button key={btn.label} onClick={()=>{setUser('Maria Silva');setLoginOpen(false);}} style={{
                width:'100%',background:btn.bg,color:btn.color,
                border:'none',padding:isMobile?'15px 24px':'13px 24px',marginBottom:12,
                fontSize:13,fontFamily:SANS,cursor:'pointer',transition:'opacity .2s',
              }}
              onMouseEnter={e=>e.currentTarget.style.opacity='.82'}
              onMouseLeave={e=>e.currentTarget.style.opacity='1'}
              >{btn.label}</button>
            ))}
            <div style={{fontSize:10,color:MUTED,lineHeight:1.8,marginTop:10,opacity:.4}}>
              Ao entrar, você concorda com os termos de uso da Badá Cheesecakes.
            </div>
          </div>
        </div>
      )}

      {/* ════════════ FOOTER ════════════════════════════════════════════════ */}
      <footer style={{background:'#050403',borderTop:`1px solid ${BORDER}`,padding:isMobile?'48px 5% 32px':'72px 5% 40px',marginTop:isMobile?0:80}}>
        <div style={{display:'grid',gridTemplateColumns:isMobile?'1fr 1fr':'repeat(auto-fit,minmax(160px,1fr))',gap:isMobile?36:48,marginBottom:isMobile?36:56}}>
          <div style={{gridColumn:isMobile?'span 2':'auto',marginBottom:isMobile?4:0}}>
            <div style={{marginBottom:16}}><LogoBada height={160}/></div>
            <p style={{fontSize:12,color:MUTED,lineHeight:2,fontWeight:300}}>
              Feito com obsessão pelo detalhe.<br/>
              Rua Emilio Mallet, 95<br/>
              Tatuapé · São Paulo – SP
            </p>
          </div>
          {[
            {title:'Redes sociais', items:SOCIALS.slice(0,3)},
            {title:'Peça agora',    items:SOCIALS.slice(3)},
          ].map(col=>(
            <div key={col.title}>
              <div style={{...lbl,fontSize:9,marginBottom:16}}>{col.title}</div>
              {col.items.map(s2=>(
                <a key={s2.l} href={s2.u} target="_blank" rel="noreferrer" style={{display:'block',fontSize:12,color:MUTED,marginBottom:12,fontWeight:300,transition:'color .2s'}}
                  onMouseEnter={e=>e.target.style.color=RED}
                  onMouseLeave={e=>e.target.style.color=MUTED}
                >{s2.l}</a>
              ))}
            </div>
          ))}
          {!isMobile&&(
            <div>
              <div style={{...lbl,fontSize:9,marginBottom:16}}>Navegação</div>
              {[['home','Início'],['menu','Cardápio'],['cart','Carrinho']].map(([p,l2])=>(
                <button key={p} onClick={()=>go(p)} style={{display:'block',fontSize:12,color:MUTED,background:'transparent',border:'none',cursor:'pointer',fontFamily:SANS,padding:'0 0 12px',textAlign:'left',transition:'color .2s'}}
                  onMouseEnter={e=>e.target.style.color=RED}
                  onMouseLeave={e=>e.target.style.color=MUTED}
                >{l2}</button>
              ))}
            </div>
          )}
        </div>
        <div style={{height:1,background:`linear-gradient(to right,${RED},transparent)`,marginBottom:20,opacity:.35}}/>
        <div style={{display:'flex',justifyContent:'space-between',flexWrap:'wrap',gap:8}}>
          <span style={{fontSize:10,color:MUTED,opacity:.3}}>© 2025 Badá Cheesecake Artesanal · São Paulo</span>
          <span style={{fontSize:10,color:MUTED,opacity:.18}}>Pagamentos e login mockados · Demo</span>
        </div>
      </footer>

      {/* BOTÃO FLUTUANTE WHATSAPP — oculto no mobile (já tem no hero e footer) */}
      {!isMobile&&(
        <a href="https://wa.me/5511933769243" target="_blank" rel="noreferrer" style={{
          position:'fixed',bottom:28,right:28,zIndex:99,
          width:52,height:52,background:'#25D366',borderRadius:'50%',
          display:'flex',alignItems:'center',justifyContent:'center',
          boxShadow:'0 4px 20px rgba(37,211,102,0.3)',transition:'transform .2s',
        }}
        onMouseEnter={e=>e.currentTarget.style.transform='scale(1.08)'}
        onMouseLeave={e=>e.currentTarget.style.transform='scale(1)'}
        >
          <svg width="24" height="24" viewBox="0 0 24 24" fill="white"><path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413z"/></svg>
        </a>
      )}

      {/* MOBILE: barra de ação fixa no rodapé */}
      {isMobile&&pg==='home'&&(
        <div className="safe-bottom" style={{
          position:'fixed',bottom:0,left:0,right:0,zIndex:99,
          background:'rgba(10,9,8,0.97)',borderTop:`1px solid ${BORDER}`,
          padding:'12px 5% 14px',display:'flex',gap:10,
        }}>
          <BtnRed onClick={()=>go('menu')} style={{flex:1,padding:'14px',textAlign:'center',fontSize:11}}>
            Montar Pedido
          </BtnRed>
          <a href="https://wa.me/5511933769243" target="_blank" rel="noreferrer" style={{
            flex:1,display:'flex',alignItems:'center',justifyContent:'center',gap:8,
            background:'rgba(37,211,102,0.12)',border:'1px solid rgba(37,211,102,0.3)',
            color:'#25D366',fontSize:11,letterSpacing:'0.12em',textTransform:'uppercase',fontFamily:SANS,
          }}>
            <svg width="14" height="14" viewBox="0 0 24 24" fill="#25D366"><path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413z"/></svg>
            WhatsApp
          </a>
        </div>
      )}
    </div>
  );
}
